interface ScrollMetrics {
  scrollLeft: number;
  scrollTop: number;
}

type ResizeDir = 'left' | 'right';

interface ResizeOverride {
  start: number;
  end: number;
}

/**
 * Single resize session model. Discriminated union over what's being
 * resized so all the handler logic lives in one place — no parallel
 * `groupResizeSessionRef` / `handleShotGroupResizePointerDown` /
 * `endGroupResize` chain to keep in sync.
 *
 * Three kinds:
 *   - 'clip': free clip resize (existing per-clip path).
 *   - 'group-child-boundary': interior boundary inside a pinned shot
 *     group. Resizing one edge moves the shared boundary; the dragged
 *     child and its neighbor change duration symmetrically.
 *   - 'group-edge': outer edge of a pinned shot group (first child's
 *     left or last child's right). Resizes the whole group.
 */
interface BaseResizeSession {
  pointerId: number;
  /** The handle's owning action — used for pointer capture & overrides. */
  actionId: string;
  rowId: string;
  dir: ResizeDir;
  initialClientX: number;
}

interface ClipResizeSession extends BaseResizeSession {
  kind: 'clip';
  initialStart: number;
  initialEnd: number;
  minStart?: number;
  maxEnd?: number;
}

interface GroupChildBoundaryResizeSession extends BaseResizeSession {
  kind: 'group-child-boundary';
  initialStart: number;
  initialEnd: number;
  adjacentActionId: string;
  adjacentInitialStart: number;
  adjacentInitialEnd: number;
  /** Absolute time bounds for the boundary so neither child goes below min. */
  minBoundary: number;
  maxBoundary: number;
}

interface GroupEdgeResizeSession extends BaseResizeSession {
  kind: 'group-edge';
  shotId: string;
  /** Absolute initial start/end of the entire group (not the dragged clip). */
  groupInitialStart: number;
  groupInitialEnd: number;
  /** All clipIds in the group — used to clear overrides on end. */
  groupClipIds: string[];
  /**
   * Snapshot of each child's initial absolute start/end so we can drive
   * per-clip preview overrides during the drag (the whole group reflows
   * proportionally with the dragged edge — visual matches the commit).
   */
  groupChildrenSnapshot: Array<{ clipId: string; start: number; end: number }>;
  /** Commit fn returned by useClipResize.startGroupEdgeResize. */
  commitResize: (deltaSeconds: number) => void;
}

type ResizeSession =
  | ClipResizeSession
  | GroupChildBoundaryResizeSession
  | GroupEdgeResizeSession;

interface PositionedShotGroup {
  key: string;
  shotId: string;
  shotName: string;
  clipIds: string[];
  start: number;
  end: number;
  rowId: string;
  color: string;
  mode?: 'images' | 'video';
  hasFinalVideo: boolean;
  hasStaleVideo: boolean;
  hasActiveTask: boolean;
  left: number;
  top: number;
  width: number;
  height: number;
}

