function applyActionBounds(
  rows: TimelineRow[],
  rowId: string,
  actionId: string,
  nextStart: number,
  nextEnd: number,
): TimelineRow[] {
  return rows.map((row) => {
    if (row.id !== rowId) return row;
    return {
      ...row,
      actions: row.actions.map((action) => (
        action.id === actionId ? { ...action, start: nextStart, end: nextEnd } : action
      )),
    };
  });
}

export function useClipResize({
  dataRef,
  applyEdit,
}: UseClipResizeArgs): UseClipResizeResult {
  const resizeStartRef = useRef<Record<string, ResizeStartState>>({});
  const resizeTransactionIdRef = useRef<Record<string, string>>({});

  const onActionResizeStart = useCallback(({ action, row, dir }: ResizeStartTarget) => {
    if (action.id.startsWith('uploading-')) return;
    const current = dataRef.current;
    const clipMeta = current?.meta[action.id];
    if (!current || !clipMeta || typeof clipMeta.hold === 'number') {
      // Hold clips don't need source-time snapshots; free-clip commit path
      // computes hold directly from the new end-start. We still want a
      // transaction id for the commit so undo groups correctly.
      resizeTransactionIdRef.current[action.id] = crypto.randomUUID();
      // Capture the minimal origin for hold clips too, so interior-boundary
      // resize has the same code path.
      if (current && clipMeta) {
        resizeStartRef.current[action.id] = {
          start: action.start,
          from: 0,
          to: action.end - action.start,
          speed: 1,
          trackKind: getTrackKind(current, row.id, clipMeta.track),
        };
      }
      return;
    }

    resizeStartRef.current[action.id] = getResizeStartState(current, action, row.id, clipMeta);
    resizeTransactionIdRef.current[action.id] = crypto.randomUUID();
    // Silence unused-dir lint; dir is consumed at end-time.
    void dir;
  }, [dataRef]);

  const onActionResizeEnd = useCallback(({
    action,
    row,
    start,
    end,
    dir,
  }: ResizeEndTarget) => {
    if (action.id.startsWith('uploading-')) return;
    const current = dataRef.current;
    const clipMeta = current?.meta[action.id];
    if (!current || !clipMeta) return;

    const transactionId = resizeTransactionIdRef.current[action.id] ?? crypto.randomUUID();
    const origin = resizeStartRef.current[action.id]
      ?? getResizeStartState(current, action, row.id, clipMeta);

    // Clamp for audio tracks.
    let clampedStart = start;
    let clampedEnd = end;
    if (origin.trackKind === 'audio') {
      if (dir === 'left') {
        const minStart = action.end - (origin.to / origin.speed);
        clampedStart = Math.max(start, minStart);
      } else if (typeof origin.assetDuration === 'number') {
        const maxEnd = action.start + Math.max(0, origin.assetDuration - origin.from) / origin.speed;
        clampedEnd = Math.min(end, maxEnd);
      }
    }
    if (clampedEnd - clampedStart < MIN_CLIP_DURATION) {
      if (dir === 'left') clampedStart = clampedEnd - MIN_CLIP_DURATION;
      else clampedEnd = clampedStart + MIN_CLIP_DURATION;
    }

    // Interior-boundary case: clip is inside a pinned group AND has a live
    // neighbor on the drag side. Update both the dragged clip AND the
    // neighbor so the neighbor's far edge stays fixed.
    const interior = getInteriorNeighbor(current, action.id, dir);
    if (interior) {
      const neighborAction = row.actions.find((a) => a.id === interior.neighborClipId);
      const neighborMeta = current.meta[interior.neighborClipId];
      if (neighborAction && neighborMeta) {
        // Primary clip new bounds.
        const primaryPatch = computeClipResizeMetaPatch(clipMeta, origin, clampedStart, clampedEnd, dir);

        // The moved boundary's new absolute position:
        //   dir=right → boundary is primary's new end, neighbor shifts its start
        //   dir=left  → boundary is primary's new start, neighbor keeps start, its end shrinks
        // Semantics per plan: clip[i].hold changes, clip[i+1].at AND hold change so clip[i+1]'s right edge stays put.
        let neighborNewStart: number;
        let neighborNewEnd: number;
        let neighborDir: ResizeDir;
        if (dir === 'right') {
          neighborNewStart = clampedEnd;
          neighborNewEnd = neighborAction.end;
          neighborDir = 'left';
        } else {
          // Plan spec covers dir=right; the symmetric case: dragging clip[i]'s left edge
          // means the boundary between clip[i-1] and clip[i] moves to `clampedStart`.
          // clip[i-1]'s left edge stays, its right edge (= hold) grows/shrinks.
          neighborNewStart = neighborAction.start;
          neighborNewEnd = clampedStart;
          neighborDir = 'right';
        }

        if (neighborNewEnd - neighborNewStart < MIN_CLIP_DURATION) {
          // Don't commit a degenerate neighbor state; fall through to single-clip
          // treatment instead (which acts like first/last edge — neighbor unchanged).
        } else {
          const neighborOrigin: ResizeStartState = {
            start: neighborAction.start,
            from: neighborMeta.from ?? 0,
            to: getSourceTime(
              { from: neighborMeta.from ?? 0, start: neighborAction.start, speed: neighborMeta.speed ?? 1 },
              neighborAction.end,
            ),
            speed: neighborMeta.speed ?? 1,
            trackKind: getTrackKind(current, row.id, neighborMeta.track),
            assetDuration: getAssetDuration(current, neighborMeta),
          };
          const neighborPatch = computeClipResizeMetaPatch(
            neighborMeta,
            neighborOrigin,
            neighborNewStart,
            neighborNewEnd,
            neighborDir,
          );

          let nextRows = applyActionBounds(current.rows, row.id, action.id, clampedStart, clampedEnd);
          nextRows = applyActionBounds(nextRows, row.id, interior.neighborClipId, neighborNewStart, neighborNewEnd);

