const getResizeContext = useCallback((actionId: string, rowId: string) => {
  const row = rows.find((candidate) => candidate.id === rowId);
  const action = row?.actions.find((candidate) => candidate.id === actionId);
  if (!row || !action) {
    return null;
  }

  const override = resizePreviewRef.current[actionId] ?? resizeOverrides[actionId];
  return {
    row,
    action: override ? { ...action, ...override } : action,
  };
}, [resizeOverrides, rows]);

// ───────────────────────────────────────────────────────────────────
// Resize: single session model for clip / group-child / group-edge.
// ───────────────────────────────────────────────────────────────────

const updateResize = useCallback((session: ResizeSession, clientX: number) => {
  const deltaSeconds = (clientX - session.initialClientX) / pixelsPerSecond;

  if (session.kind === 'group-child-boundary') {
    // Move the shared boundary between two adjacent children. The dragged
    // child and its neighbor change duration symmetrically; everyone else
    // in the group stays put.
    const initialBoundary = session.dir === 'left' ? session.initialStart : session.initialEnd;
    const proposed = initialBoundary + deltaSeconds;
    const clamped = Math.min(Math.max(proposed, session.minBoundary), session.maxBoundary);
    const wasClamped = clamped !== proposed;

    const draggedOverride = session.dir === 'left'
      ? { start: clamped, end: session.initialEnd }
      : { start: session.initialStart, end: clamped };
    const adjacentOverride = session.dir === 'left'
      ? { start: session.adjacentInitialStart, end: clamped }
      : { start: clamped, end: session.adjacentInitialEnd };

    resizePreviewRef.current[session.actionId] = draggedOverride;
    resizePreviewRef.current[session.adjacentActionId] = adjacentOverride;
    setResizeOverrides((current) => ({
      ...current,
      [session.actionId]: draggedOverride,
      [session.adjacentActionId]: adjacentOverride,
    }));
    setResizeClampedActionId((current) => (
      wasClamped ? session.actionId : current === session.actionId ? null : current
    ));
    return;
  }

  if (session.kind === 'group-edge') {
    // Resize the entire pinned shot group's outer edge. Snap against
    // sibling clips on the row that aren't part of the group.
    const minimumDuration = 0.05;
    let start: number;
    let end: number;
    if (session.dir === 'left') {
      start = clamp(session.groupInitialStart + deltaSeconds, 0, session.groupInitialEnd - minimumDuration);
      end = session.groupInitialEnd;
    } else {
      start = session.groupInitialStart;
      end = Math.max(session.groupInitialStart + minimumDuration, session.groupInitialEnd + deltaSeconds);
    }

    const row = rows.find((candidate) => candidate.id === session.rowId);
    if (row) {
      const groupClipIdSet = new Set(session.groupClipIds);
      const siblings = row.actions.filter((a) => !groupClipIdSet.has(a.id));
      const snapThresholdS = SNAP_THRESHOLD_PX / pixelsPerSecond;
      const snapped = snapResize(start, end, session.dir, siblings, `${session.shotId}:${session.rowId}`, snapThresholdS);
      start = snapped.start;
      end = snapped.end;
    }

    if (end - start < minimumDuration) {
      if (session.dir === 'left') start = end - minimumDuration;
      else end = start + minimumDuration;
    }

    // Project each child's preview position by scaling the original
    // group's interval [groupInitialStart, groupInitialEnd] onto
    // [start, end]. This mirrors what resizeGroupEdge does on commit so
    // the live preview matches the committed result exactly.
    const originalDuration = session.groupInitialEnd - session.groupInitialStart;
    const newDuration = end - start;
    const scale = originalDuration > 0 ? newDuration / originalDuration : 1;
    const childOverrides: Record<string, ResizeOverride> = {};
    for (const child of session.groupChildrenSnapshot) {
      const childOriginalOffset = child.start - session.groupInitialStart;
      const childOriginalDuration = child.end - child.start;
      const newChildStart = start + childOriginalOffset * scale;
      const newChildEnd = newChildStart + childOriginalDuration * scale;
      childOverrides[child.clipId] = { start: newChildStart, end: newChildEnd };
    }

    const groupKey = `${session.shotId}:${session.rowId}`;
    resizePreviewRef.current[groupKey] = { start, end };
    for (const [clipId, override] of Object.entries(childOverrides)) {
      resizePreviewRef.current[clipId] = override;
    }
    setResizeOverrides((current) => ({
      ...current,
      [groupKey]: { start, end },
      ...childOverrides,
    }));
    return;
  }

  // session.kind === 'clip' — free clip resize.
  let start = session.dir === 'left'
    ? clamp(session.initialStart + deltaSeconds, 0, session.initialEnd - minDuration)
    : session.initialStart;
  let end = session.dir === 'right'
    ? Math.max(session.initialStart + minDuration, session.initialEnd + deltaSeconds)
    : session.initialEnd;

  const row = rows.find((r) => r.id === session.rowId);
  if (row) {
    const snapThresholdS = SNAP_THRESHOLD_PX / pixelsPerSecond;
    const snapped = snapResize(start, end, session.dir, row.actions, session.actionId, snapThresholdS);
    start = snapped.start;
    end = snapped.end;
  }

  if (end - start < minDuration) {
    if (session.dir === 'left') start = end - minDuration;
    else end = start + minDuration;
  }

  let resizeClamped = false;
  if (typeof session.minStart === 'number' && start < session.minStart) {
    start = session.minStart;
    resizeClamped = true;
  }
  if (typeof session.maxEnd === 'number' && end > session.maxEnd) {
    end = session.maxEnd;
    resizeClamped = true;
  }

  const context = getResizeContext(session.actionId, session.rowId);
  if (!context) return;

  resizePreviewRef.current[session.actionId] = { start, end };
  setResizeOverrides((current) => ({
    ...current,
    [session.actionId]: { start, end },
  }));
  setResizeClampedActionId((current) => (
    resizeClamped ? session.actionId : current === session.actionId ? null : current
  ));
  onActionResizing?.({
    action: { ...context.action, start, end },
    row: context.row,
    start,
    end,
    dir: session.dir,
  });
}, [getResizeContext, minDuration, onActionResizing, pixelsPerSecond, rows]);

const endResize = useCallback((event: ReactPointerEvent<HTMLDivElement>, cancelled: boolean) => {
  const session = resizeSessionRef.current;
  if (!session || session.pointerId !== event.pointerId) return;

  resizeSessionRef.current = null;
  if (event.currentTarget.hasPointerCapture(event.pointerId)) {
    event.currentTarget.releasePointerCapture(event.pointerId);
  }
  pendingOpsRef.current -= 1;
  if (interactionStateRef) {
    interactionStateRef.current.resize = false;
    notifyInteractionEndIfIdle(interactionStateRef);
  }
  setResizeClampedActionId((current) => (current === session.actionId ? null : current));

  if (session.kind === 'group-edge') {
    const groupKey = `${session.shotId}:${session.rowId}`;
    const preview = resizePreviewRef.current[groupKey] ?? resizeOverrides[groupKey];
    if (!cancelled && preview) {
      const deltaSeconds = session.dir === 'left'
        ? preview.start - session.groupInitialStart
        : preview.end - session.groupInitialEnd;
      session.commitResize(deltaSeconds);
    }
    clearResizeOverrides([groupKey, ...session.groupClipIds]);
    return;
  }

  if (session.kind === 'group-child-boundary') {
    const context = getResizeContext(session.actionId, session.rowId);
    if (!cancelled && context) {
      onActionResizeEnd?.({
        action: context.action,
        row: context.row,
        start: context.action.start,
        end: context.action.end,
        dir: session.dir,
      });
    }
    clearResizeOverrides([session.actionId, session.adjacentActionId]);
    return;
  }

  // session.kind === 'clip'
