    setPointerCapture: {
      configurable: true,
      value(pointerId: number) {
        getPointerCaptures(this).add(pointerId);
      },
    },
    releasePointerCapture: {
      configurable: true,
      value(pointerId: number) {
        getPointerCaptures(this).delete(pointerId);
      },
    },
    hasPointerCapture: {
      configurable: true,
      value(pointerId: number) {
        return getPointerCaptures(this).has(pointerId);
      },
    },
  });
});

