import type { DragSession } from '@/tools/video-editor/hooks/useClipDrag';
import type { MarqueeRect } from '@/tools/video-editor/hooks/useMarqueeSelect';

interface ScrollMetrics {
  scrollLeft: number;
  scrollTop: number;
}

interface ResizeOverride {
  start: number;
  end: number;
}

/**
 * Single resize session model. Discriminated union over what's being
 * resized so all the handler logic lives in one place — no parallel
 * `groupResizeSessionRef` / `handleShotGroupResizePointerDown` /
 * `endGroupResize` chain to keep in sync.
 *
 * Three kinds:
 *   - 'clip': free clip resize (existing per-clip path).
 *   - 'group-child-boundary': interior boundary inside a pinned shot
 *     group. Resizing one edge moves the shared boundary; the dragged
 *     child and its neighbor change duration symmetrically.
 *   - 'group-edge': outer edge of a pinned shot group (first child's
 *     left or last child's right). Resizes the whole group.
 */
interface BaseResizeSession {
  pointerId: number;
  /** The handle's owning action — used for pointer capture & overrides. */
  actionId: string;
  rowId: string;
  dir: ResizeDir;
  initialClientX: number;
}

interface ClipResizeSession extends BaseResizeSession {
  kind: 'clip';
  initialStart: number;
  initialEnd: number;
  minStart?: number;
  maxEnd?: number;
}

interface GroupChildBoundaryResizeSession extends BaseResizeSession {
  kind: 'group-child-boundary';
  initialStart: number;
  initialEnd: number;
  adjacentActionId: string;
  adjacentInitialStart: number;
  adjacentInitialEnd: number;
}

interface GroupEdgeResizeSession extends BaseResizeSession {
  kind: 'group-edge';
  shotId: string;
  /** Absolute initial start/end of the entire group (not the dragged clip). */
  groupInitialStart: number;
  groupInitialEnd: number;
  /** All clipIds in the group — used to clear overrides on end. */
  groupClipIds: string[];
  /**
   * Snapshot of each child's initial absolute start/end so we can drive
   * per-clip preview overrides during the drag (the whole group reflows
   * proportionally with the dragged edge — visual matches the commit).
   */
  groupChildrenSnapshot: Array<{ clipId: string; start: number; end: number }>;
  /** Commit fn returned by useClipResize.startGroupEdgeResize. */
  commitResize: (deltaSeconds: number) => void;
}

type ResizeSession =
  | ClipResizeSession
  | GroupChildBoundaryResizeSession
  | GroupEdgeResizeSession;

interface PositionedShotGroup {
  key: string;
  shotId: string;
  shotName: string;
  clipIds: string[];
  start: number;
  end: number;
  rowId: string;
  color: string;
  mode?: 'images' | 'video';
  hasFinalVideo: boolean;
  hasStaleVideo: boolean;
  hasActiveTask: boolean;
  left: number;
  top: number;
  width: number;
  height: number;
}

export interface TimelineCanvasProps {
  rows: TimelineRow[];
  tracks: TrackDefinition[];
  scale: number;
  scaleWidth: number;
  scaleSplitCount: number;

---
    return {
      row,
      action: override ? { ...action, ...override } : action,
    };
  }, [resizeOverrides, rows]);

  // ───────────────────────────────────────────────────────────────────
  // Resize: single session model for clip / group-child / group-edge.
  // ───────────────────────────────────────────────────────────────────

  const updateResize = useCallback((session: ResizeSession, clientX: number) => {
    const deltaSeconds = (clientX - session.initialClientX) / pixelsPerSecond;

    if (session.kind === 'group-child-boundary') {
      // Move the shared boundary between two adjacent children. The dragged
      // child and its neighbor change duration symmetrically; everyone else
      // in the group stays put.
      const initialBoundary = session.dir === 'left' ? session.initialStart : session.initialEnd;
      const resized = computeGroupChildBoundaryResize({
        dir: session.dir,
        dragged: { start: session.initialStart, end: session.initialEnd },
        adjacent: { start: session.adjacentInitialStart, end: session.adjacentInitialEnd },
        proposedBoundary: initialBoundary + deltaSeconds,
        minimumDuration: MIN_GROUP_RESIZE_DURATION,
      });
      const draggedOverride = resized.dragged;
      const adjacentOverride = resized.adjacent;

      resizePreviewRef.current[session.actionId] = draggedOverride;
      resizePreviewRef.current[session.adjacentActionId] = adjacentOverride;
      setResizeOverrides((current) => ({
        ...current,
        [session.actionId]: draggedOverride,
        [session.adjacentActionId]: adjacentOverride,
      }));
      setResizeClampedActionId((current) => (
        resized.wasClamped ? session.actionId : current === session.actionId ? null : current
      ));
      return;
    }

