    const relativeX = clientX - rect.left + scrollLeft;
    return clamp(pixelToTime(relativeX), 0, maxTime);
  };

  const handlePointerDown = (event: React.PointerEvent<HTMLDivElement>) => {
    if (event.button !== 0) {
      return;
    }

    pointerSessionRef.current = {
      pointerId: event.pointerId,
      startClientX: event.clientX,
      isDragging: false,
    };
    event.currentTarget.setPointerCapture(event.pointerId);
    event.preventDefault();
  };

  const handlePointerMove = (event: React.PointerEvent<HTMLDivElement>) => {
    const session = pointerSessionRef.current;
    if (!session || session.pointerId !== event.pointerId) {
      return;
    }

    if (!session.isDragging && Math.abs(event.clientX - session.startClientX) >= POINTER_DRAG_THRESHOLD_PX) {
      session.isDragging = true;
    }

    if (!session.isDragging) {
      return;
    }

    onCursorDrag(clientXToTime(event.clientX));
  };

  const finishPointerSession = (
    event: React.PointerEvent<HTMLDivElement>,
    cancelled: boolean,
  ) => {
    const session = pointerSessionRef.current;
    if (!session || session.pointerId !== event.pointerId) {
      return;
    }

    pointerSessionRef.current = null;
    if (event.currentTarget.hasPointerCapture(event.pointerId)) {
      event.currentTarget.releasePointerCapture(event.pointerId);
    }

    if (cancelled) {
      return;
    }

    const time = clientXToTime(event.clientX);
    if (session.isDragging) {
      onCursorDrag(time);
      return;
    }

    onClickTimeArea(time);
  };

  return (
    <div
      ref={containerRef}
      className="relative h-[30px] overflow-hidden border-b border-border bg-card/80 select-none"
    >
      <div
        className="absolute inset-y-0 left-0"
        style={{
          width: contentWidth,
          transform: `translateX(${-scrollLeft}px)`,
        }}
      >
        <div
          className="absolute inset-y-0 left-0 border-r border-border/70 bg-card/90"
          style={{ width: startLeft }}
        />

        {minorTicks.map((tick) => (
          <div
            key={tick.key}
            className={tick.isMajor ? 'absolute bottom-0 w-px bg-border/80' : 'absolute bottom-0 w-px bg-border/35'}
            style={{
              left: tick.left,
              height: tick.isMajor ? '100%' : '45%',
            }}
          />
        ))}

        {majorTicks.map((tick) => (
          <div
            key={tick.key}
            className="pointer-events-none absolute left-0 top-0"

        initial: { start: session.groupInitialStart, end: session.groupInitialEnd },
        proposedBoundary: session.dir === 'left' ? snapped.start : snapped.end,
        minimumDuration: MIN_GROUP_RESIZE_DURATION,
      }));
    }

    // Project each child's preview position by scaling the original
    // group's interval [groupInitialStart, groupInitialEnd] onto
    // [start, end]. This mirrors what resizeGroupEdge does on commit so
    // the live preview matches the committed result exactly.
    const originalDuration = session.groupInitialEnd - session.groupInitialStart;
    const newDuration = end - start;
    const scale = originalDuration > 0 ? newDuration / originalDuration : 1;
    const childOverrides: Record<string, ResizeOverride> = {};
    for (const child of session.groupChildrenSnapshot) {
      const childOriginalOffset = child.start - session.groupInitialStart;
      const childOriginalDuration = child.end - child.start;
      const newChildStart = start + childOriginalOffset * scale;
      const newChildEnd = newChildStart + childOriginalDuration * scale;
      childOverrides[child.clipId] = { start: newChildStart, end: newChildEnd };
    }

    const groupKey = `${session.shotId}:${session.rowId}`;
    resizePreviewStore.merge({
      [groupKey]: { start, end },
      ...childOverrides,
    });
    return;
  }

  // session.kind === 'clip' — free clip resize.
  let start = session.dir === 'left'
    ? clamp(cursorBoundaryTime, 0, session.initialEnd - minDuration)
    : session.initialStart;
  let end = session.dir === 'right'
    ? Math.max(session.initialStart + minDuration, cursorBoundaryTime)
    : session.initialEnd;

  const row = rows.find((r) => r.id === session.rowId);
  if (row) {
    const snapThresholdS = SNAP_THRESHOLD_PX / pixelsPerSecond;
    const snapped = snapResize(start, end, session.dir, row.actions, session.actionId, snapThresholdS);
    start = snapped.start;
    end = snapped.end;
  }

  if (end - start < minDuration) {
    if (session.dir === 'left') start = end - minDuration;
    else end = start + minDuration;
  }

  let resizeClamped = false;
  if (typeof session.minStart === 'number' && start < session.minStart) {
    start = session.minStart;
    resizeClamped = true;
  }
  if (typeof session.maxEnd === 'number' && end > session.maxEnd) {
    end = session.maxEnd;
    resizeClamped = true;
  }

  const context = getResizeContext(session.actionId, session.rowId);
  if (!context) return;

  resizePreviewStore.merge({
    [session.actionId]: { start, end },
  });
  setResizeClampedActionId((current) => (
    resizeClamped ? session.actionId : current === session.actionId ? null : current
  ));
  onActionResizing?.({
    action: { ...context.action, start, end },
    row: context.row,
    start,
    end,
    dir: session.dir,
  });
}, [getResizeContext, minDuration, onActionResizing, pixelsPerSecond, resizePreviewStore, rows, startLeft]);

const endResize = useCallback((event: ReactPointerEvent<HTMLDivElement>, cancelled: boolean) => {
  const session = resizeSessionRef.current;
  if (!session || session.pointerId !== event.pointerId) return;

  resizeSessionRef.current = null;
  if (event.currentTarget.hasPointerCapture(event.pointerId)) {
    event.currentTarget.releasePointerCapture(event.pointerId);
  }
  pendingOpsRef.current -= 1;
  if (interactionStateRef) {
    interactionStateRef.current.resize = false;
    notifyInteractionEndIfIdle(interactionStateRef);
  }
  setResizeClampedActionId((current) => (current === session.actionId ? null : current));

  if (session.kind === 'group-edge') {
    const groupKey = `${session.shotId}:${session.rowId}`;
    const preview = resizePreviewStore.getSnapshot()[groupKey];
    if (!cancelled && preview) {
      const deltaSeconds = session.dir === 'left'
        ? preview.start - session.groupInitialStart
        : preview.end - session.groupInitialEnd;
      session.commitResize(deltaSeconds);
    }
    clearResizePreview([groupKey, ...session.groupClipIds]);
    return;
  }

  if (session.kind === 'group-child-boundary') {
    const context = getResizeContext(session.actionId, session.rowId);
    if (!cancelled && context) {
      onActionResizeEnd?.({
        action: context.action,
        row: context.row,
        start: context.action.start,
        end: context.action.end,
        dir: session.dir,
      });
    }
    clearResizePreview([session.actionId, session.adjacentActionId]);
    return;
  }

  // session.kind === 'clip'
  const context = getResizeContext(session.actionId, session.rowId);
  if (!cancelled && context) {
    onActionResizeEnd?.({
      action: context.action,
      row: context.row,
      start: context.action.start,
      end: context.action.end,
      dir: session.dir,
    });
  }
  clearResizePreview([session.actionId]);
}, [clearResizePreview, getResizeContext, interactionStateRef, onActionResizeEnd, pendingOpsRef, resizePreviewStore]);

